const FIRST_ROAR_BADGE_SRC = "/images/badges/postl1.png";
const toBadgeImageSrc = (imageUrl: string) => {
  if (/^(https?:)?\/\//.test(imageUrl) || imageUrl.startsWith("/")) return imageUrl;
  return `/images/badges/${imageUrl}`;
};



